```python
def longestCommonPrefix(arr1, arr2):
    prefix_set = set()

    for num in arr1:
        s = str(num)
        for i in range(1, len(s) + 1):
            prefix_set.add(s[:i])

    max_len = 0
    for num in arr2:
        s = str(num)
        for i in range(len(s), 0, -1):
            if s[:i] in prefix_set:
                max_len = max(max_len, i)
                break

    return max_len
